"use client";

import { useRouter } from "next/navigation";
import { useAuth } from "../../context/AuthContext";
import { useEffect } from "react";
import ProtectedRoute from "../../components/ProtectedRoute";

export default function DtkofPage() {
    const { access } = useAuth(); // Get access array from AuthContext
    const router = useRouter();

    useEffect(() => {
        if (!access.includes("dtkof")) {
            // Redirect if the user doesn't have access
            router.push("/dashboard");
        }
    }, [access, router]);

    return (
        <ProtectedRoute>
            <div className="min-h-screen bg-black text-gray-200 p-6">
                <h1 className="text-3xl font-bold mb-4">Data Konsolidator Offline</h1>
                <p>Welcome to the Data Konsolidator Offline page.</p>
            </div>
        </ProtectedRoute>
    );
}
